SELECT AVG(T1.edge_density), AVG(T1.bluriness), AVG(T2.file_size)
FROM images AS T1
JOIN image_files AS T2 ON T1.image_id = T2.image_id;

SELECT images.image_id, image_files.file_id
FROM images
JOIN image_files ON images.image_id = image_files.image_id;

SELECT image_id
FROM images
WHERE image_resolution = '4K';
